import React, { useState } from "react";
import MissionItem from "./MissionItem";

const initialTasks = [
  { id: 1, text: "Đạt 10 điểm", completed: false },
  { id: 2, text: "Tránh 5 ống liên tiếp", completed: false },
  { id: 3, text: "Chơi 3 lượt", completed: false },
];

function MissionBoard() {
  const [tasks, setTasks] = useState(initialTasks);

  const toggleTask = (id) => {
    setTasks((prev) =>
      prev.map((task) =>
        task.id === id ? { ...task, completed: !task.completed } : task
      )
    );
  };

  return (
    <div className="max-w-md mx-auto p-4 shadow-lg rounded bg-yellow-100">
      <h2 className="text-xl font-bold mb-4">🎯 Nhiệm vụ Flappy Bird</h2>
      {tasks.map((task) => (
        <MissionItem key={task.id} task={task} toggleTask={toggleTask} />
      ))}
    </div>
  );
}

export default MissionBoard;
